/* Wikilink styles */
.wikilink {
  text-decoration: none;
  transition: color 0.15s;
}
.wikilink::before,
.wikilink::after {
  font-family: var(--font-mono);
  font-size: 0.72em;
  opacity: 0.45;
  vertical-align: 0.08em;
  transition: opacity 0.15s;
