     3→import { useState } from 'react';
     4→import { IconType } from 'react-icons';
     5→import { FaXTwitter, FaFacebook, FaLinkedin, FaWeibo, FaRedditAlien, FaTelegram, FaMastodon, FaHackerNews } from 'react-icons/fa6';
     6→import { SiBluesky, SiDouban, SiZhihu } from 'react-icons/si';
     7→import { LuLink, LuCheck } from 'react-icons/lu';
     8→import { siteConfig } from '../../site.config';
     9→import { useLanguage } from './LanguageProvider';
    10→
    11→interface ShareBarProps {
    12→  url: string;
    13→  title: string;
    14→  className?: string;
    15→}
    16→
    17→type Platform =
    18→  | 'twitter' | 'facebook' | 'linkedin' | 'weibo'
    19→  | 'reddit' | 'hackernews' | 'telegram' | 'bluesky' | 'mastodon'
    20→  | 'douban' | 'zhihu'
    21→  | 'copy';
    22→
    23→const PLATFORM_META: Record<Platform, { label: string; Icon: IconType }> = {
    24→  twitter:    { label: 'X / Twitter', Icon: FaXTwitter },
    25→  facebook:   { label: 'Facebook',    Icon: FaFacebook },
    26→  linkedin:   { label: 'LinkedIn',    Icon: FaLinkedin },
    27→  weibo:      { label: '微博',         Icon: FaWeibo },
    28→  reddit:     { label: 'Reddit',      Icon: FaRedditAlien },
    29→  hackernews: { label: 'Hacker News', Icon: FaHackerNews },
    30→  telegram:   { label: 'Telegram',    Icon: FaTelegram },
    31→  bluesky:    { label: 'Bluesky',     Icon: SiBluesky },
    32→  mastodon:   { label: 'Mastodon',    Icon: FaMastodon },
    33→  douban:     { label: '豆瓣',         Icon: SiDouban },
    34→  zhihu:      { label: '知乎',         Icon: SiZhihu },
    35→  copy:       { label: 'Copy link',   Icon: LuLink },
    36→};
    37→
    38→function getShareUrl(platform: Platform, url: string, title: string): string {
    39→  const eu = encodeURIComponent(url);
    40→  const et = encodeURIComponent(title);
    41→  const combined = encodeURIComponent(`${title} ${url}`);
    42→  switch (platform) {
    43→    case 'twitter':    return `https://twitter.com/intent/tweet?text=${et}&url=${eu}`;
    44→    case 'facebook':   return `https://www.facebook.com/sharer/sharer.php?u=${eu}`;
    45→    case 'linkedin':   return `https://www.linkedin.com/sharing/share-offsite/?url=${eu}`;
    46→    case 'weibo':      return `https://service.weibo.com/share/share.php?url=${eu}&title=${et}`;
    47→    case 'reddit':     return `https://www.reddit.com/submit?url=${eu}&title=${et}`;
    48→    case 'hackernews': return `https://news.ycombinator.com/submitlink?u=${eu}&t=${et}`;
    49→    case 'telegram':   return `https://t.me/share/url?url=${eu}&text=${et}`;
    50→    case 'bluesky':    return `https://bsky.app/intent/compose?text=${combined}`;
    51→    case 'mastodon':   return `https://mastodon.social/share?text=${combined}`;
    52→    case 'douban':     return `https://www.douban.com/share/service?href=${eu}&name=${et}`;
    53→    case 'zhihu':      return `https://www.zhihu.com/share?href=${eu}&type=text&title=${et}`;
    54→    case 'copy':       return '';
    55→  }
    56→}
    57→
    58→export default function ShareBar({ url, title, className = '' }: ShareBarProps) {
    59→  const { t } = useLanguage();
    60→  const [copied, setCopied] = useState(false);
    61→
    62→  if (!siteConfig.share?.enabled) return null;
    63→  const configured = siteConfig.share?.platforms ?? [];
    64→  const platforms = configured.filter((p): p is Platform => p in PLATFORM_META);
    65→  if (platforms.length === 0) return null;
    66→
    67→  const handleCopy = async () => {
    68→    try {
    69→      await navigator.clipboard.writeText(url);
    70→      setCopied(true);
    71→      setTimeout(() => setCopied(false), 2000);
    72→    } catch {
    73→      // clipboard not available
    74→    }
    75→  };
    76→
    77→  const btnClass = 'inline-flex items-center justify-center w-8 h-8 rounded text-muted hover:text-accent hover:bg-muted/10 transition-colors';
    78→
    79→  return (
    80→    <div className={`flex flex-row flex-wrap gap-1 ${className}`}>
    81→      {platforms.map((platform) => {
    82→        const { label, Icon } = PLATFORM_META[platform];
    83→
    84→        if (platform === 'copy') {
    85→          const copyLabel = copied ? t('link_copied') : t('copy_link');
    86→          return (
    87→            <button
    88→              key={platform}
