'use client';

import Script from 'next/script';
import { siteConfig } from '../../site.config';

export default function Analytics() {
  const { provider, umami, plausible, google } = siteConfig.analytics;

  if (provider === 'umami' && umami.websiteId) {
    return (
      <Script
        src={umami.src}
        data-website-id={umami.websiteId}
        strategy="afterInteractive"
      />
    );
  }

  if (provider === 'plausible' && plausible.domain) {
    return (
      <Script
        src={plausible.src}
        data-domain={plausible.domain}
        strategy="afterInteractive"
      />
    );
  }

  if (provider === 'google' && google.measurementId) {
    return (
      <>
        <Script
          src={`https://www.googletagmanager.com/gtag/js?id=${google.measurementId}`}
          strategy="afterInteractive"
        />
        <Script id="google-analytics" strategy="afterInteractive">
          {`
            window.dataLayer = window.dataLayer || [];
            function gtag(){dataLayer.push(arguments);}
            gtag('js', new Date());
            gtag('config', '${google.measurementId}');
          `}
        </Script>
      </>
    );
  }

  return null;
}

export interface NavChildItem {
  name: string;
  url: string;
  external?: boolean;
  dividerBefore?: boolean; // render a separator line before this item
}

export interface NavItem {
  name: string;
  url: string;
  weight: number;
  external?: boolean;
  dropdown?: string[];
  children?: NavChildItem[]; // static sub-links rendered as a dropdown
}

// Defined up-front so footer.connect can reference these URLs without duplication
const social = {
  github: "https://github.com/hutusi/amytis",
  twitter: "https://twitter.com/hutusi",
  email: "mailto:huziyong@gmail.com",
};

export const siteConfig = {

  // ── Site identity ─────────────────────────────────────────────────────────
  title: { en: "Amytis", zh: "Amytis" },
